+    : fFont(*font)
+    , fTextAlign(SkTextUtils::Align::kLeft_Align)
+    , fTextEncoding(SkTextEncoding::kUTF8)
+    , fFilterQuality(SkFilterQuality::None)
+    , fLcdRenderText(font->getEdging() == SkFont::Edging::kSubpixelAntiAlias)
+{
+    updateFontEdging();
+}
